squares = [(0,1), (0,4), (0,9), (1,6), (2,5), (3,6), (4,9), (6,4), (8,1)]

def can_display(S, D):
    if D not in [6,9]:
        return D in S
    else:
        return 6 in S or 9 in S

combos = list(itertools.combinations(range(10), 6))
count = 0
for i in range(len(combos)):
