        S1 = set(combos[i])
        S2 = set(combos[j])
        all_good = True
        for A, B in squares:
            if not ((can_display(S1, A) and can_display(S2, B)) or (can_display(S1, B) and can_display(S2, A))):
                all_good = False
                break
        if all_good:
            count += 1
