import itertools
from fractions import Fraction
def operate(x, op, y):
    if op == '+':
        return x + y
    elif op == '-':
        return x - y
    elif op == '*':
        return x * y
    elif op == '/':
        if y == 0:
            raise ZeroDivisionError
        return x / y
def get_possible_integers(nums):
    possible = set()
    perms = list(itertools.permutations(nums))
    def eval1(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(A, op1, B)
            temp2 = operate(temp1, op2, C)
            result = operate(temp2, op3, D)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    def eval2(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(B, op2, C)
            temp2 = operate(A, op1, temp1)
            result = operate(temp2, op3, D)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    def eval3(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(B, op2, C)
            temp2 = operate(temp1, op3, D)
            result = operate(A, op1, temp2)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    def eval4(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(C, op3, D)
            temp2 = operate(B, op2, temp1)
            result = operate(A, op1, temp2)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    def eval5(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(A, op1, B)
            temp2 = operate(C, op3, D)
            result = operate(temp1, op2, temp2)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    evaluators = [eval1, eval2, eval3, eval4, eval5]
    for perm in perms:
        a, b, c, d = perm
        for ops in itertools.product(['+', '-', '*', '/'], repeat=3):
            for evaluator in evaluators:
                result = evaluator(a, b, c, d, ops[0], ops[1], ops[2])
                if result is not None:
                    possible.add(result)
    return possible
