MAX_N = 1000000

total_sum_div = [0] * (MAX_N + 1)
for i in range(1, MAX_N + 1):
    for j in range(i, MAX_N + 1, i):
        total_sum_div[j] += i

proper_sum_div = [0] * (MAX_N + 1)
for i in range(1, MAX_N + 1):
    proper_sum_div[i] = total_sum_div[i] - i

succ = [0] * (MAX_N + 1)
for i in range(1, MAX_N + 1):
    next_val = proper_sum_div[i]
    if 1 <= next_val <= MAX_N:
        succ[i] = next_val

visited = [False] * (MAX_N + 1)
max_length = 0
smallest_in_longest = float('inf')

for start in range(1, MAX_N + 1):
    if not visited[start]:
        path = []
        current = start
        while 1 <= current <= MAX_N and not visited[current]:
            visited[current] = True
            path.append(current)
            current = succ[current]
        if 1 <= current <= MAX_N and current in path:
            index = path.index(current)
            cycle = path[index:]
            cycle_length = len(cycle)
            if cycle_length > max_length:
                max_length = cycle_length
                smallest_in_longest = min(cycle)
            elif cycle_length == max_length:
                smallest_in_longest = min(smallest_in_longest, min(cycle))

print(smallest_in_longest)
